// Cache-aside read + write with correct invalidation (delete, don't update).
// Includes single-flight to prevent a thundering herd on cache miss.

import type Redis from "ioredis";

const TTL_SECONDS = 60; // short: bounds staleness even if an invalidation is missed
const inFlight = new Map<string, Promise<Product | null>>();

async function getProduct(redis: Redis, db: Db, id: string): Promise<Product | null> {
  const key = `product:${id}`;

  const cached = await redis.get(key);
  if (cached !== null) {
    return cached === "__MISS__" ? null : JSON.parse(cached); // cache negatives too
  }

  // Single-flight: collapse concurrent misses into one DB load per process.
  if (inFlight.has(key)) return inFlight.get(key)!;

  const load = (async () => {
    const row = await db.products.findById(id);
    // SET NX-style with jitter avoids synchronized expiry (avalanche).
    const ttl = TTL_SECONDS + Math.floor(Math.random() * 10);
    await redis.set(key, row ? JSON.stringify(row) : "__MISS__", "EX", ttl);
    return row;
  })().finally(() => inFlight.delete(key));

  inFlight.set(key, load);
  return load;
}

async function updateProduct(redis: Redis, db: Db, id: string, patch: Partial<Product>) {
  await db.products.update(id, patch);   // 1. source of truth first
  await redis.del(`product:${id}`);       // 2. invalidate: next read repopulates
  // Do NOT redis.set(new value) here: a concurrent read could have just written
  // an older snapshot, leaving a stale value that outlives this write. Deleting
  // is safe because the next miss reloads the committed row.

// Bounded pool with load shedding beats an unbounded queue under overload.
// AbortPolicy rejects immediately when saturated -> fail fast, don't melt down.

ExecutorService pool = new ThreadPoolExecutor(
    16,                                  // core threads
    16,                                  // max threads (sized ~= CPU cores for CPU-bound)
    30, TimeUnit.SECONDS,
    new ArrayBlockingQueue<>(200),       // BOUNDED queue: the backpressure signal
    new ThreadPoolExecutor.AbortPolicy() // shed load: throw RejectedExecutionException
);

try {
    pool.submit(task);
} catch (RejectedExecutionException e) {
    // Translate to a fast 503 with Retry-After. This protects tail latency for
    // the requests already in flight instead of degrading everyone equally.
    return Response.status(503).header("Retry-After", "1").build();
}

// Anti-pattern: new LinkedBlockingQueue<>() (unbounded). Under overload it hides
// the problem by accepting everything, memory and latency grow without limit,
// and Little's Law guarantees in-flight count -> infinity until OOM.

// Debounce: run the expensive work only after input has settled.
// Used for search-as-you-type to cut request volume and main-thread work.
function debounce(fn, waitMs) {
  let timer = null;
  const debounced = (...args) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), waitMs);
  };
  debounced.cancel = () => clearTimeout(timer);
  return debounced;
}

// 300ms is a good default for search: fast enough to feel live, slow enough that
// a typist's burst collapses to ONE request instead of one per keystroke.
const onSearch = debounce((q) => fetchResults(q), 300);
searchInput.addEventListener("input", (e) => onSearch(e.target.value));

// Throttle (contrast): guarantees at most one call per interval, for continuous
// streams like scroll/resize where you want steady updates, not a final one.
function throttle(fn, intervalMs) {
  let last = 0;
  return (...args) => {
    const now = Date.now();
    if (now - last >= intervalMs) { last = now; fn(...args); }
  };
}

// k6 load test with a ramp profile and percentile thresholds.
// Run: k6 run cart-load.js
import http from "k6/http";
import { check, sleep } from "k6";

export const options = {
  stages: [
    { duration: "30s", target: 50 },   // warm-up ramp (let caches/JIT settle)
    { duration: "2m",  target: 500 },  // ramp to target load
    { duration: "3m",  target: 500 },  // steady state -> read percentiles HERE
    { duration: "30s", target: 0 },    // ramp down
  ],
  thresholds: {
    http_req_duration: ["p(95)<200", "p(99)<500"], // SLO as a gate
    http_req_failed: ["rate<0.01"],                 // <1% errors
  },
};

export default function () {
  const res = http.get("https://staging.example.com/api/cart", {
    headers: { Authorization: `Bearer ${__ENV.TOKEN}` },
  });
  check(res, { "status 200": (r) => r.status === 200 });
  sleep(1); // model think-time so you measure realistic concurrency
}

// BEFORE: N+1 -> one query per team.
async function loadDashboard(userId: string) {
  const teams = await db.teams.findByUser(userId);      // 1 query
  for (const team of teams) {
    team.members = await db.members.findByTeam(team.id); // N queries (the N+1)
  }
  return assemble(teams);
}

// AFTER: batched load -> two queries total, regardless of team count.
async function loadDashboard(userId: string) {
  const teams = await db.teams.findByUser(userId);       // 1 query
  const ids = teams.map((t) => t.id);
  const members = await db.members.findByTeams(ids);     // 1 query: WHERE team_id IN (...)
  const byTeam = groupBy(members, (m) => m.teamId);
  for (const team of teams) team.members = byTeam.get(team.id) ?? [];
  return assemble(teams);
}
// Combined with CREATE INDEX ON team_members(team_id) and a 60s cache-aside
// layer, p99 went 2.3s -> 210ms. Each change was measured independently so we
// know the N+1 fix bought ~1.4s and the index bought ~0.7s.

