import type Redis from "ioredis";

const BASE_TTL = 30;                 // seconds: prices change rarely; 30s bounds staleness
const inFlight = new Map<string, Promise<Price | null>>();

export async function getPrice(redis: Redis, db: Db, sku: string): Promise<Price | null> {
  const key = `price:${sku}`;
  const cached = await redis.get(key);
  if (cached !== null) {
    return cached === "__MISS__" ? null : JSON.parse(cached); // cache negatives to stop DB probing
  }

  // Single-flight: one DB load per key per process, even under 5000 rps of misses.
  const existing = inFlight.get(key);
  if (existing) return existing;

  const load = (async () => {
    const row = await db.prices.findBySku(sku);
    const ttl = BASE_TTL + Math.floor(Math.random() * 10); // jitter: avoid synchronized expiry
    await redis.set(key, row ? JSON.stringify(row) : "__MISS__", "EX", ttl);
    return row;
  })().finally(() => inFlight.delete(key));

  inFlight.set(key, load);
  return load;
}

export async function updatePrice(redis: Redis, db: Db, sku: string, price: Price): Promise<void> {
  await db.prices.upsert(sku, price);   // 1. write source of truth first
  await redis.del(`price:${sku}`);       // 2. INVALIDATE by deletion (not overwrite)
  // Optional: publish an invalidation event so in-process/local caches on other
  // nodes drop the key too: await redis.publish("price-invalidate", sku);
}
